import csv
qs = []
with open('market.csv', 'r') as f:
    reader = csv.DictReader(f)
    for row in reader:
        if row['is_resolved'] == 'False':
            qs.append(row)

# Check near-term resolution dates
from datetime import datetime
import json

for q in qs:
    rd = q['resolution_date']
    if rd:
        try:
            dt = datetime.strptime(rd, '%Y-%m-%d')
            if dt <= datetime(2026, 1, 25):
                pred = q['my_prediction']
                print(f\"qid={q['qid']} | res={rd} | pred={pred[:80] if pred else 'NONE'}... | title={q['title'][:80]}\")
        except:
            pass
print(f'Total active: {len(qs)}')
"
